INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Smart booking page$q$, $q$A hosted booking page that syncs with Google Calendar, Outlook, and iCloud so clients only ever see genuinely available times.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Zero-commission payments$q$, $q$Accepts payments via Stripe, PayU, Przelewy24, and tPay without Zencal taking a cut beyond standard processor fees.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Automated reminders$q$, $q$SMS and email reminders sent ahead of appointments to help reduce no-shows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Team scheduling$q$, $q$Round-robin assignment across multiple specialists plus shared team analytics for managers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Bundles and events$q$, $q$Sell service packages, memberships, and group events, not just single one-off appointments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Automatic invoicing$q$, $q$Invoices are generated and sent to clients automatically after a paid booking.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$API and integrations$q$, $q$REST API, webhooks, and native connections to Zapier, Make, n8n, and HubSpot.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$EU-hosted data$q$, $q$Data stored in EU data centers with end-to-end encryption to support GDPR compliance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$No added commission on payments beyond standard processing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Combines scheduling, payments, and invoicing in one product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Strong fit for GDPR-conscious European service businesses$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Flat-rate Team plan can be cost-effective for larger staffs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Native integrations with Zapier, Make, n8n, and HubSpot$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Entry-level Light plan excludes payments and analytics$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Newer company (founded 2022) with a smaller track record than established competitors like Calendly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Team plan caps at 20 users before requiring a custom Enterprise quote$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Fewer third-party integrations than larger scheduling platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$What is Zencal used for?$q$, $q$Zencal is used by service professionals and teams to let clients book appointments online, pay for services, receive automated reminders, and get invoices, all from one hosted booking page.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Does Zencal charge a commission on payments?$q$, $q$No. Zencal advertises zero commission on payments processed through its Pro, Team, and Enterprise plans, beyond the standard fees charged by the payment processor itself.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Is there a free trial?$q$, $q$Yes, Zencal offers a 14-day free trial with full access to Pro-tier features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Can multiple team members share one Zencal account?$q$, $q$Yes. The Pro plan supports unlimited users, and the Team plan is built specifically for staffs of up to 20 with round-robin assignment and shared analytics.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$What payment methods does Zencal support?$q$, $q$Zencal integrates with Stripe, PayU, Przelewy24, and tPay, giving both international and Central European businesses local payment options.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Does Zencal integrate with other tools?$q$, $q$Yes. Zencal offers a REST API, webhooks, and native integrations with Zapier, Make, n8n, and HubSpot.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Where is Zencal's data hosted?$q$, $q$Zencal hosts data in EU data centers with end-to-end encryption, which supports GDPR compliance for European customers.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Who is Zencal best suited for?$q$, $q$Zencal is best suited for solo consultants, healthcare practitioners, coaches, and multi-specialist service businesses that want scheduling, payments, and invoicing in one tool.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Solo practitioner booking$q$, $q$A single consultant or coach uses Zencal's hosted page to let clients self-book and pay for sessions without manual back-and-forth.$q$, $q$Independent consultants and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Multi-specialist clinics$q$, $q$A clinic with several practitioners uses round-robin assignment and a shared client portal to distribute bookings evenly across staff.$q$, $q$Healthcare and wellness practices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Package and membership sales$q$, $q$A fitness studio sells class bundles and memberships through Zencal's Bundles and Events modules instead of one-off bookings only.$q$, $q$Fitness studios and group service providers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Light$q$, $q$$10 per user per month$q$, $q$monthly or annual (2 months free annually)$q$, NULL, $q$["1 user","Unlimited meetings and topics","Unlimited calendar connections","Hosted profile page","Email notifications","Zoom integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Pro$q$, $q$$28 per user per month$q$, $q$monthly or annual (2 months free annually)$q$, NULL, $q$["Unlimited users","Payments and invoicing with no added commission","Email and SMS notifications","Zoom, Webex, and calendar integrations","HubSpot integration","API and webhooks"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Team$q$, $q$$349 per month flat$q$, $q$monthly or annual (2 months free annually)$q$, NULL, $q$["Up to 20 users","All Pro features plus Events, Bundles, Analytics, and Client Portal","Round robin assignment","Priority support and configuration assistance"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["20-plus users","Dedicated infrastructure","Custom domain or subdomain","Dedicated Slack channel and account manager","SLA guarantee"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$overview$q$, $q$What Is Zencal$q$, 2, ARRAY[$q$Zencal is a service-sales and booking platform designed for professionals who sell appointments, consultations, or sessions rather than physical products. Instead of stitching together a calendar tool, a payment processor, and a separate reminder system, Zencal bundles scheduling, payments, invoicing, and notifications into one hosted booking page.$q$, $q$The company is based in Krakow, Poland and was founded in 2022. Its EU roots show up in the product: data is hosted in EU data centers with end-to-end encryption, and local European payment methods like Przelewy24 and tPay sit alongside Stripe, making it a natural fit for European service businesses that need GDPR-aligned infrastructure.$q$, $q$Zencal targets a wide range of service professionals, from individual consultants and healthcare practitioners to fitness trainers, coaches, and multi-specialist clinics that need to coordinate several calendars under one brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zencal's core is a public booking page that syncs with Google Calendar, Outlook, and iCloud so clients only see genuinely open times. Around that core, the platform layers commerce features: built-in payment collection with no added Zencal commission, automatic invoice generation, and SMS plus email reminders meant to reduce no-shows.$q$, $q$For teams, Zencal adds round-robin lead assignment across specialists, a shared client portal, and team-level analytics so managers can see booking volume and revenue per staff member. Businesses that sell more than single appointments can package services into bundles, memberships, or group events.$q$, $q$Developers and marketing teams can connect Zencal to other systems through its REST API, webhooks, and native integrations with Zapier, Make, n8n, and HubSpot, allowing booking data to flow into a CRM or automation pipeline.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bef9e8d8-86d1-4254-b054-8fdc286672d5', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zencal offers four tiers. Light starts at about $10 per user per month for one user and covers unlimited meetings, calendar connections, and a hosted profile page, but excludes payments, invoicing, and analytics.$q$, $q$Pro, at roughly $28 per user per month with unlimited users, unlocks payments and invoicing with no added Zencal commission, SMS and email notifications, video conferencing integrations, and API access. Team, a flat $349 per month for up to 20 users, adds every module (events, bundles, analytics, client portal), round robin, and priority support.$q$, $q$An Enterprise tier for 20-plus users offers custom pricing, dedicated infrastructure, a custom domain, and a dedicated account manager. Annual billing on any tier saves the equivalent of about two months, and a 14-day free trial gives full access to Pro features before purchase.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Local multi-track recording$q$, $q$Each participant's audio and video is recorded locally and uploaded separately, avoiding quality loss from live call compression.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$4K video and 48kHz WAV audio$q$, $q$Supports high-resolution video and studio-grade uncompressed audio for post-production.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$ZenAI text-based editing$q$, $q$Edit recordings by cutting text from an auto-generated transcript instead of manually scrubbing a timeline.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$AI clip generation$q$, $q$Automatically produces short, social-media-ready clips from longer podcast or video episodes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Near-automatic transcription$q$, $q$Generates transcripts advertised at around 99 percent accuracy for English recordings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Hosting and analytics$q$, $q$Hosts finished audio and video episodes with performance analytics for listeners and viewers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Mobile recording$q$, $q$Hosts and guests can record full-quality podcast episodes directly from a smartphone.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Built-in monetization$q$, $q$Provides tools for creators to generate revenue directly from their content on the platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$High local-recording quality that isn't limited by participants' internet connections$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Transcript-based editing significantly speeds up post-production$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Free tier lets creators test the platform before paying$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Combines recording, editing, hosting, and monetization in one product$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Mobile recording extends usability beyond the desktop$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Higher-tier features like extended mixing time and more seats require the pricier plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$AI clipping and editing tools can require a learning curve for non-technical users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Positioned at a premium relative to some lower-cost recording tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Video features and limits vary noticeably between plans$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$What is Zencastr used for?$q$, $q$Zencastr is used to remotely record, edit, transcribe, and host podcasts and video content, letting hosts and guests record from separate locations at studio-level quality.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Does Zencastr have a free plan?$q$, $q$Yes, Zencastr offers a free tier for testing core recording features, alongside paid plans that unlock more recording time, higher resolution, and additional tools.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$What audio and video quality does Zencastr support?$q$, $q$Zencastr supports up to 4K video recording and 48kHz 16-bit WAV audio, with each participant's track captured and uploaded separately.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Does Zencastr include transcription?$q$, $q$Yes, Zencastr includes automatic transcription advertised at around 99 percent accuracy for English content, and transcripts can be used to edit recordings directly.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Can I record a podcast on my phone with Zencastr?$q$, $q$Yes, Zencastr supports mobile recording so hosts and guests can capture episodes from a smartphone.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Who founded Zencastr?$q$, $q$Zencastr was founded in 2014 by Adrian Lopez and Josh Nielsen.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Does Zencastr offer AI clipping for social media?$q$, $q$Yes, Zencastr's AI tools can automatically generate short clips from longer episodes for sharing on social platforms.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Is Zencastr suitable for video interviews, not just audio podcasts?$q$, $q$Yes, Zencastr supports 4K video recording and is used by podcasters, video creators, and professionals conducting remote interviews.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Interview-style podcasting$q$, $q$A host records separate high-quality audio and video tracks with remote guests, then edits the conversation using the transcript-based editor.$q$, $q$Independent and professional podcasters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Social clip production$q$, $q$A creator records a long-form episode and uses AI clipping to generate short highlight videos for social media distribution.$q$, $q$Video creators and content marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Remote research interviews$q$, $q$A journalist or researcher records a high-fidelity remote interview and relies on the built-in transcript for note-taking and quotes.$q$, $q$Journalists and researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Core recording features","Limited recording and mixing time","Good for testing the platform before upgrading"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Standard$q$, $q$Around $20 per month$q$, $q$monthly or annual (annual discount)$q$, NULL, $q$["Unlimited audio recordings","1080p video recording","MP3 and 16-bit 48kHz WAV recording","Limited monthly mixing hours","Unlimited English transcription"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Grow$q$, $q$Around $30 per month$q$, $q$monthly or annual (annual discount)$q$, NULL, $q$["Everything in Standard","More mixing and editing time","Additional collaboration features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Scale$q$, $q$Around $50 per month$q$, $q$monthly or annual (annual discount)$q$, NULL, $q$["Everything in Grow","Higher usage limits for growing shows","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$Business$q$, $q$Around $100 per month$q$, $q$monthly or annual (annual discount)$q$, NULL, $q$["Everything in Scale","Highest usage limits","Built for teams and agencies producing multiple shows"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$overview$q$, $q$What Is Zencastr$q$, 2, ARRAY[$q$Zencastr is a remote recording platform purpose-built for podcasters, video creators, and interviewers. Rather than relying on a video call tool where quality depends on everyone's internet connection at the moment of the call, Zencastr records each participant's audio and video locally in the browser or app and uploads it separately, so the final file quality is not limited by the weakest connection in the room.$q$, $q$Founded in 2014 by Adrian Lopez and Josh Nielsen and based in Cottonwood Heights, Utah, Zencastr has grown from a recording-only tool into a broader production suite covering recording, AI-assisted editing, transcription, hosting, and monetization.$q$, $q$The platform serves podcasters running interview-style shows, video creators who need clean multi-track source files, and researchers or journalists conducting remote interviews that need a reliable, high-fidelity recording.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Recording quality is Zencastr's foundation: up to 4K video and 48kHz 16-bit WAV audio, captured per participant and uploaded separately so each track can be mixed and edited independently. Recording works from desktop browsers as well as mobile devices, letting guests join without installing special software.$q$, $q$On the editing side, Zencastr's ZenAI tools let users edit audio and video like a text document, cutting words or sections directly from a transcript instead of scrubbing a waveform. A live soundboard supports sound effects during recording, and AI clipping automatically generates short, social-ready clips from longer episodes.$q$, $q$Rounding out the workflow, Zencastr includes near-automatic transcription, hosting and distribution for finished episodes, performance analytics, and monetization tools that let creators earn directly through the platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55291a7c-44cc-4c8d-8410-f9af5ea79a43', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zencastr uses a freemium model. A free tier gives new users a way to try core recording features before committing to a subscription, and paid plans layer on more recording and mixing time, higher resolution, more transcription, and additional seats.$q$, $q$Reported paid tiers include a Standard plan around $20 per month, Grow around $30, Scale around $50, and Business around $100, with roughly 20 percent savings for annual billing over monthly. A 14-day free trial is available on paid plans.$q$, $q$Larger organizations with custom needs, such as media companies producing many shows, can request Enterprise pricing directly from Zencastr's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Unified ticketing$q$, $q$Consolidates customer conversations from email, chat, phone, and social channels into a single ticket with full history.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Omnichannel support$q$, $q$Lets a single conversation move across channels, such as starting in chat and continuing over email, without losing context.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$AI agents and Copilot$q$, $q$AI-driven agents can resolve routine tickets automatically, while a Copilot layer assists human agents with summaries and reply suggestions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Help center and knowledge base$q$, $q$Customizable self-service portal where customers can find answers without contacting an agent.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Automation and triggers$q$, $q$Rules-based automation for routing, escalating, and prioritizing tickets based on defined conditions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Reporting and analytics$q$, $q$Dashboards tracking response times, resolution rates, and customer satisfaction scores.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$App marketplace$q$, $q$A large marketplace of integrations connecting Zendesk to CRMs, e-commerce platforms, and internal tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Voice and workforce management add-ons$q$, $q$Optional paid modules for call center functionality and agent scheduling.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Mature, widely adopted platform with a large integration ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Strong omnichannel ticketing that keeps conversation context across channels$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Robust reporting and customization for larger support operations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$AI agent and Copilot features for automating routine resolutions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Scales from small teams to large enterprise support organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$AI features and voice or workforce add-ons carry extra per-agent costs on top of base plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Top-tier Enterprise plan requires a custom sales quote rather than published pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Can be more expensive than smaller competitors like Freshdesk at comparable feature levels$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Initial setup and configuration can be complex for smaller teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$What is Zendesk used for?$q$, $q$Zendesk is used by support teams to manage customer service conversations across email, chat, phone, and social media from a unified ticketing system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$How much does Zendesk cost?$q$, $q$Zendesk's entry-level Support Team plan starts around $19 per agent per month, while bundled Suite plans start around $55 per agent per month for Suite Team, with higher tiers and AI add-ons priced separately.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Does Zendesk include AI features?$q$, $q$Yes, Zendesk offers AI agents that can resolve routine tickets automatically and a Copilot assistant that helps human agents, both typically sold as add-ons.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Who owns Zendesk?$q$, $q$Zendesk is privately owned, following a roughly $10.2 billion acquisition in November 2022 led by investment firms Hellman and Friedman and Permira.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$What is the difference between Zendesk Support and Zendesk Suite?$q$, $q$Support plans cover core ticketing only, while Suite plans bundle ticketing with live chat, a help center, and voice capabilities.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Does Zendesk have a CRM product?$q$, $q$Yes, Zendesk offers a separate sales CRM called Zendesk Sell that can be used alongside or independently of the core support product.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$What integrations does Zendesk support?$q$, $q$Zendesk offers a large app marketplace with integrations for CRMs, e-commerce platforms, communication tools, and many other business systems.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Is there a free trial for Zendesk?$q$, $q$Zendesk typically offers a free trial period for prospective customers to test its ticketing and support features before subscribing.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Multi-channel customer support$q$, $q$A support team consolidates email, chat, and social media inquiries into one ticketing queue to respond consistently across channels.$q$, $q$Customer support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Self-service deflection$q$, $q$A company builds a public help center of articles so customers can resolve common issues without opening a ticket, reducing agent workload.$q$, $q$Support operations and customer experience teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$AI-assisted ticket resolution$q$, $q$A support organization deploys AI agents to automatically resolve routine, repetitive tickets while routing complex issues to human agents.$q$, $q$Enterprise support and operations leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Support Team$q$, $q$$19 per agent per month$q$, $q$annual$q$, NULL, $q$["Core ticketing","Email, chat, and social channel support","Basic automation and reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Suite Team$q$, $q$$55 per agent per month$q$, $q$annual$q$, NULL, $q$["Ticketing plus live chat, help center, and basic voice","Standard automation and reporting","App marketplace access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Suite Professional$q$, $q$$115 per agent per month$q$, $q$annual$q$, NULL, $q$["Everything in Suite Team","Advanced reporting and analytics","Skills-based routing and SLA management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$Suite Enterprise (with Copilot)$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Everything in Suite Professional","Copilot AI included","Advanced customization, security, and workflow controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$overview$q$, $q$What Is Zendesk$q$, 2, ARRAY[$q$Zendesk is a customer service platform that helps support teams manage conversations across email, chat, phone, and social media from a single ticketing system. Founded in 2007 and headquartered in San Francisco, it is one of the most established names in the help-desk software category.$q$, $q$In late 2022, Zendesk was acquired by a group of investors led by Hellman and Friedman and Permira in a deal valued at approximately $10.2 billion, taking the company private. It continues to operate at significant scale, with roughly 7,000 employees serving customers globally.$q$, $q$Zendesk is used across industries by teams ranging from small support desks to large enterprise customer service operations, and it is frequently paired with its companion CRM product, Zendesk Sell, for teams that also want a sales pipeline in the same ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The foundation of Zendesk is its ticketing system, which consolidates customer messages from every connected channel into a single conversation thread, complete with customer history, tags, and internal notes for agents. Because it is omnichannel, a conversation can move between chat, email, and phone without losing context.$q$, $q$Zendesk has added significant AI capability in recent years: AI agents that can independently resolve routine tickets, and a Copilot assistant that helps human agents by summarizing conversations, drafting replies, and suggesting next actions. These AI features are typically sold as add-ons on top of the base subscription.$q$, $q$Beyond ticketing and AI, Zendesk includes a customizable help center for self-service articles, automation and triggers for routing tickets, detailed reporting on response times and satisfaction scores, and an extensive app marketplace for integrating with CRMs, e-commerce tools, and internal systems.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b87bf8ae-75dd-4294-97a0-45d392ce365a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zendesk prices per agent per month, with annual billing offering lower rates than month-to-month. The entry-level Support Team plan starts around $19 per agent per month for basic ticketing.$q$, $q$For teams that want ticketing bundled with chat, help center, and voice, the Suite plans start around $55 per agent per month for Suite Team and around $115 per agent per month for Suite Professional on an annual contract. Monthly billing runs meaningfully higher than these annual rates.$q$, $q$The top-tier Suite Enterprise plan, now marketed as Enterprise plus Copilot, is sold on a custom quote rather than a published price. AI features, voice, and workforce management are generally available as paid add-ons layered on top of any base plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Visual sales pipeline$q$, $q$A customizable pipeline that tracks deals from lead to close and highlights where deals stall.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Email integration$q$, $q$Syncs with Gmail and Outlook to automatically log communications and support templates and tracking.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sales sequences$q$, $q$Automated email and task sequences for multi-step lead outreach without manual follow-up tracking.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sales forecasting$q$, $q$Predicts deal volume and revenue based on pipeline data to support planning and goal setting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Prebuilt and custom reporting$q$, $q$Around 20 prebuilt dashboards plus a drag-and-drop report builder for custom analytics.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Mobile CRM with geolocation$q$, $q$Full-featured iOS and Android apps that let field reps manage deals and see nearby prospects.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Product catalog$q$, $q$Available on higher tiers, letting reps attach standardized products and pricing to deals.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Shared Zendesk data$q$, $q$Connects to Zendesk Support data so sales reps can see a prospect's customer service history.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Strong, highly rated mobile app for field sales teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Straightforward, activity-focused CRM that's easier to set up than heavier enterprise platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Native email tracking and sequences reduce manual data entry$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Can share customer data with Zendesk Support for full context$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Prebuilt dashboards give quick visibility without custom report building$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Per-seat pricing climbs quickly for teams needing Professional or Enterprise features$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Fewer deep sales-engagement features than dedicated sales engagement platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Enterprise-tier pricing requires higher spend for advanced customization$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Less brand recognition as a standalone CRM compared to Zendesk's support product$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$What is Zendesk Sell?$q$, $q$Zendesk Sell is Zendesk's sales CRM product, separate from Zendesk's customer support ticketing platform, built for managing leads, deals, and sales pipelines.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$How much does Zendesk Sell cost?$q$, $q$Zendesk Sell starts around $19 per user per month for the Team plan on annual billing, scaling up to around $169 per user per month for the Enterprise plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Is Zendesk Sell the same as Zendesk Support?$q$, $q$No. Zendesk Sell is a distinct sales CRM product, while Zendesk Support and Suite are Zendesk's customer service ticketing products, though they can be connected within the same account.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Does Zendesk Sell have a mobile app?$q$, $q$Yes, Zendesk Sell offers a full-featured mobile CRM app for iOS and Android with geolocation for field sales reps.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Can Zendesk Sell automate sales outreach?$q$, $q$Yes, Zendesk Sell supports email and task sequences that automate multi-step outreach to leads.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Does Zendesk Sell integrate with email?$q$, $q$Yes, it syncs with Gmail and Outlook to automatically log emails and support templates and tracking.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Who is Zendesk Sell best for?$q$, $q$Zendesk Sell is best suited for small to mid-sized sales teams that want a straightforward, activity-driven CRM, particularly those already using Zendesk for support.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Does Zendesk Sell offer sales forecasting?$q$, $q$Yes, Zendesk Sell includes forecasting tools that predict deal volume and revenue based on pipeline activity.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Pipeline-driven B2B sales$q$, $q$A sales team tracks deals through a customizable pipeline and uses forecasting to plan quarterly targets.$q$, $q$B2B sales teams and sales managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Field sales management$q$, $q$Reps use the mobile app with geolocation to log visits, update deals, and check nearby prospects while traveling.$q$, $q$Field and outside sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Support-to-sales visibility$q$, $q$A company running both Zendesk Support and Sell gives sales reps access to a prospect's support ticket history before a renewal conversation.$q$, $q$Companies using both Zendesk Support and Sell$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sell Team$q$, $q$$19 per user per month annually ($25 monthly)$q$, $q$annual or monthly$q$, NULL, $q$["Up to 3 paid users","Single custom sales pipeline","Email integration","Mobile CRM app"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sell Growth$q$, $q$$55 per user per month annually ($69 monthly)$q$, $q$annual or monthly$q$, NULL, $q$["Everything in Team","Prospecting tools","Sales forecasting","Advanced reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sell Professional$q$, $q$$115 per user per month annually ($149 monthly)$q$, $q$annual or monthly$q$, NULL, $q$["Everything in Growth","Two custom sales pipelines","Advanced automation and customization","Product catalog"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sell Enterprise$q$, $q$Around $169 per user per month$q$, $q$annual$q$, NULL, $q$["Everything in Professional","Highest usage capacity","Custom notifications and task automation","Enterprise administrative controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$overview$q$, $q$What Is Zendesk Sell$q$, 2, ARRAY[$q$Zendesk Sell is Zendesk's dedicated sales CRM, distinct from the company's better-known customer support ticketing product. While it shares the Zendesk brand and account infrastructure, Sell is built, priced, and sold as its own product for managing leads, deals, and sales pipelines.$q$, $q$Sell is aimed at sales teams that want a straightforward, activity-driven CRM rather than a heavily customized enterprise sales platform. Its visual pipeline, native email tracking, and mobile app make it particularly popular with field sales teams and small to mid-sized B2B sales organizations.$q$, $q$Because it runs on the same Zendesk account, companies that already use Zendesk for customer support can connect Sell to give sales reps visibility into a prospect's or customer's support ticket history.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core of Zendesk Sell is a customizable visual sales pipeline that tracks deals from lead to close, helping reps and managers spot where deals are stalling. Email syncing with Gmail and Outlook automatically logs communications, and email and task sequences let teams automate multi-step outreach.$q$, $q$Sales forecasting tools help predict deal volume and revenue based on pipeline data, and around 20 pre-built dashboards give teams quick visibility into performance metrics, with a drag-and-drop builder available for custom reports.$q$, $q$A fully featured mobile app for iOS and Android, including geolocation for field sales, lets reps manage deals, log calls, and check their pipeline away from a desk. Higher-tier plans add automation, a product catalog, and deeper customization.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zendesk Sell is priced per user per month across four tiers, with annual billing offering lower rates than paying monthly. Sell Team starts around $19 per user per month annually, or about $25 billed monthly.$q$, $q$Sell Growth runs around $55 per user per month annually (about $69 monthly), adding prospecting tools and more advanced reporting. Sell Professional is around $115 per user per month annually (about $149 monthly), adding deeper customization and automation.$q$, $q$Sell Enterprise, the top tier, runs around $169 per user per month and includes the highest usage capacity, additional custom pipelines, and enterprise-level administrative controls.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$S3 API compatibility$q$, $q$Implements the Amazon S3 API so existing S3-based applications and SDKs work without code changes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Multi-cloud backend support$q$, $q$Can use local file storage or route to Amazon S3, Azure Blob Storage, or Google Cloud Storage as the underlying backend.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Docker-based deployment$q$, $q$Official Docker images allow a working instance to be running within minutes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Open-source and Apache 2.0 licensed$q$, $q$Free to use, modify, and redistribute, including in commercial products, with no licensing fees.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Multi-language SDK support$q$, $q$Works with standard AWS SDKs for Python, Java, Node.js, .NET, and other languages.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Vendor lock-in avoidance$q$, $q$Stores raw, unmodified data rather than proprietary formats, making it easier to move between backends.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Local S3 testing$q$, $q$Lets developers test S3-dependent application code locally without connecting to a live AWS account.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Active open-source maintenance$q$, $q$Maintained by Scality's engineering team with ongoing commits, releases, and community contributions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Completely free and open source under a permissive Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Full S3 API compatibility means minimal to no code changes for existing S3 applications$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Supports multiple cloud backends, reducing vendor lock-in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Fast Docker-based deployment suited to local development and CI/CD$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Backed by an established storage vendor (Scality) with an active open-source community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Requires self-hosting and infrastructure management, unlike a managed cloud storage service$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$No official paid support tier included with the open-source project itself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Best suited for developers comfortable with Docker and Node.js-based tooling$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Enterprise-grade features and support require Scality's separate commercial products$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$What is Zenko CloudServer?$q$, $q$Zenko CloudServer is a free, open-source object storage server that implements the Amazon S3 API, allowing S3-compatible applications to run on-premises or across multiple cloud providers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Is Zenko CloudServer free?$q$, $q$Yes, CloudServer is completely free and open source under the Apache License 2.0, with no licensing fees for the software itself.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Who maintains Zenko CloudServer?$q$, $q$Zenko CloudServer is maintained by Scality, a data storage company founded in 2009, along with an active open-source community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$What cloud backends does CloudServer support?$q$, $q$CloudServer supports a local file system backend as well as cloud backends including Amazon S3, Microsoft Azure Blob Storage, and Google Cloud Storage.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$How is Zenko CloudServer deployed?$q$, $q$CloudServer is most commonly deployed via Docker, with an official image that allows a working instance to be running within minutes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Is Zenko CloudServer the same as Amazon S3?$q$, $q$No, it is a separate open-source server that implements the S3 API, so S3-compatible applications can run against it, but it is not operated by AWS.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$What programming languages does CloudServer support?$q$, $q$CloudServer works with standard AWS SDKs for languages including Python, Java, Node.js, and .NET, since it implements the same S3 API those SDKs already use.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Who typically uses Zenko CloudServer?$q$, $q$It's typically used by developers building S3-compatible applications, enterprises wanting multi-cloud storage flexibility, and teams testing S3-dependent code locally.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Local S3 development and testing$q$, $q$A development team runs CloudServer in Docker to test S3-dependent application code without connecting to a live AWS account.$q$, $q$Software developers and QA teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Multi-cloud storage abstraction$q$, $q$An enterprise uses CloudServer to present a single S3-style API in front of both Azure Blob Storage and Google Cloud Storage, avoiding vendor lock-in.$q$, $q$Enterprise infrastructure and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$On-premises S3-compatible storage$q$, $q$An organization with data sovereignty requirements deploys CloudServer on its own hardware to get S3-compatible storage without using a public cloud.$q$, $q$Regulated enterprises and data centers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full S3 API compatibility","Local file system and multi-cloud backend support","Docker deployment","Apache 2.0 license, no fees"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$overview$q$, $q$What Is Zenko CloudServer$q$, 2, ARRAY[$q$Zenko CloudServer is an open-source object storage server that implements the Amazon S3 API, letting developers run S3-compatible storage anywhere, not just on AWS. It was originally released by Scality in June 2016 as S3 Server and was renamed CloudServer and folded into the broader Zenko multi-cloud data controller project in 2017.$q$, $q$Scality, the company behind CloudServer, was founded in 2009 and is headquartered in San Francisco, California, with major engineering operations in Paris. CloudServer remains one of Scality's flagship open-source projects and continues to see active development on GitHub.$q$, $q$The project is written in Node.js and released under the Apache License 2.0, making it free to use, modify, and redistribute, including as part of commercial products, without licensing fees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CloudServer's core feature is full S3 API compatibility, which means existing applications and tools written against Amazon's S3 API, including AWS SDKs for Python, Java, Node.js, and .NET, work against a CloudServer instance without code changes.$q$, $q$It supports multiple storage backends: a local file system backend suited to development and testing, and cloud backends including Amazon S3, Microsoft Azure Blob Storage, and Google Cloud Storage, letting teams present one consistent S3-style API across otherwise incompatible cloud storage systems.$q$, $q$Deployment is designed to be fast, with an official Docker image that lets developers spin up a working instance within minutes, making CloudServer popular for local development, CI/CD pipelines, and testing S3-dependent code without a live AWS account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zenko CloudServer is completely free and open source under the Apache License 2.0. There are no license fees, seat costs, or paid tiers for the core software.$q$, $q$Costs come only from the infrastructure you run it on, such as compute, storage, and any commercial cloud backend it's connected to (for example, actual AWS S3 or Azure Blob Storage usage fees when using those as a backend).$q$, $q$Scality also offers commercial, enterprise-grade storage products separately from the open-source CloudServer project for organizations that want vendor support and additional features beyond the free software.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('38a2e613-81b8-4dd1-a50b-c900db574bb3', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Contract-based billing automation$q$, $q$Generates invoices directly from contract data across flat, usage-based, hybrid, and custom pricing models.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Usage metering$q$, $q$Handles prepaid and postpaid credits, including credit expiry and rollover for usage-based billing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Revenue recognition$q$, $q$Produces audit-ready revenue schedules without manual spreadsheet work.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Collections and dunning$q$, $q$Automates payment reminders and dunning workflows to reduce late payments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Contract builder$q$, $q$Lets finance teams configure complex pricing and contract terms without engineering involvement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$SaaS metrics analytics$q$, $q$Pre-built reports on MRR, ARR, LTV, and RPO with AI-powered insights.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Agents Marketplace$q$, $q$Customizable AI agents that can be chained together to automate specific finance workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Broad integrations$q$, $q$Connects to more than 100 CRMs, CPQ tools, ERPs, payment gateways, and data warehouses.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Handles complex usage-based and hybrid pricing models that spreadsheets struggle with$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Combines billing, revenue recognition, and collections in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$All plan tiers include full feature access and unlimited support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$SOC 2, ISO 27001, and GDPR certified, suited to security-conscious B2B buyers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Broad integration library with CRMs, ERPs, and payment gateways$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Pricing is entirely custom, making upfront cost comparison difficult$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Best suited for companies with real billing complexity, potentially more than simple subscription businesses need$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$As a newer company (founded 2022), it has a shorter track record than incumbents like Zuora$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Full value depends on integrating multiple existing systems (CRM, ERP, payment gateway)$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$What does Zenskar do?$q$, $q$Zenskar automates billing, revenue recognition, and collections for SaaS and technology companies, generating invoices and revenue schedules directly from contract and usage data.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$How much does Zenskar cost?$q$, $q$Zenskar does not publish fixed prices. It offers Start, Standard, and Enterprise tiers, each quoted based on a customer's contract volume and complexity.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Who founded Zenskar?$q$, $q$Zenskar was founded in 2022 by Saurabh Agrawal and Apurv Bansal.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Does Zenskar support usage-based billing?$q$, $q$Yes, usage-based and metered billing, including prepaid and postpaid credits with expiry and rollover, is a core part of Zenskar's platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Does Zenskar handle revenue recognition?$q$, $q$Yes, Zenskar automates revenue recognition into audit-ready schedules without manual spreadsheet work.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$What integrations does Zenskar offer?$q$, $q$Zenskar connects to more than 100 systems, including CRMs, CPQ tools, ERPs, payment gateways, and data warehouses.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Is Zenskar suitable for small startups?$q$, $q$Zenskar is generally best suited for growing SaaS and technology companies with meaningful billing complexity, such as usage-based or hybrid pricing, rather than very early-stage companies with simple flat subscriptions.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Does Zenskar offer a free trial or sandbox?$q$, $q$Yes, Zenskar offers a sandbox environment where prospects can test the platform before committing to a plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Usage-based SaaS billing$q$, $q$A SaaS company with metered or consumption-based pricing uses Zenskar to automatically generate accurate invoices from usage data.$q$, $q$Usage-based and API-first SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Automated revenue recognition$q$, $q$A finance team replaces manual spreadsheet-based revenue recognition with Zenskar's audit-ready automated schedules.$q$, $q$Finance and accounting teams at growing SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Collections automation$q$, $q$A revenue operations team sets up automated dunning workflows in Zenskar to reduce overdue invoices without manual chasing.$q$, $q$Revenue operations and collections teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Start$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Full platform feature access","Unlimited support","Suited to earlier-stage billing needs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Standard$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Full platform feature access","Unlimited support","Suited to growing billing complexity"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Full platform feature access","Unlimited support","Suited to high-volume, complex contract and usage billing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$overview$q$, $q$What Is Zenskar$q$, 2, ARRAY[$q$Zenskar is a revenue automation platform built to handle the full order-to-cash workflow for SaaS and technology companies, from generating invoices to recognizing revenue to chasing down late payments. It's designed specifically for companies with complex or usage-based pricing models that outgrow manual, spreadsheet-driven billing processes.$q$, $q$Founded in 2022 by Saurabh Agrawal and Apurv Bansal and headquartered in New York City, Zenskar has raised a Series A round reported at around $15 million and holds SOC 2, ISO 27001, and GDPR compliance certifications.$q$, $q$The platform is marketed as AI-native, layering AI-powered insights and configurable AI agents on top of its core billing, revenue recognition, and collections functionality.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Zenskar generates invoices directly from contract data, supporting flat subscriptions, usage-based or metered pricing, hybrid pricing, and custom negotiated terms, without finance teams calculating charges manually in spreadsheets. Its metering engine also handles prepaid and postpaid credits, including credit expiry and rollover.$q$, $q$Zenskar automates revenue recognition into audit-ready schedules and includes a collections module with automated payment reminders and dunning workflows to reduce overdue invoices. A contract builder lets non-technical finance teams configure complex pricing without engineering support.$q$, $q$For visibility, Zenskar provides pre-built analytics on core SaaS metrics like MRR, ARR, LTV, and RPO, plus an Agents Marketplace of customizable AI agents that can be chained together for specific finance workflows. Over 100 integrations connect Zenskar to CRMs, CPQ tools, ERPs, payment gateways, and data warehouses.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de85e666-3a6a-4ce4-b304-a77397acde17', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zenskar does not publish fixed prices. It offers three named tiers, Start, Standard, and Enterprise, each priced with a custom quote based on a company's contract volume, complexity, and required features.$q$, $q$Regardless of tier, Zenskar states that customers get access to all platform features and unlimited support without additional charges, differentiating it from vendors that gate features behind higher-priced plans.$q$, $q$Prospective customers can test the platform in a sandbox environment before committing, and pricing conversations happen directly with Zenskar's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Physically simulated combat$q$, $q$Units and projectiles follow real physics rather than purely scripted animations, affecting how battles play out.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Terrain manipulation$q$, $q$Players can dig, raise, or flatten terrain mid-match to build ramps, canals, or fortifications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$100-plus unit types$q$, $q$A large roster of units with distinct abilities supports varied strategies and playstyles.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Customizable commanders$q$, $q$Player commander units can be built around different ability sets and strategies.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Non-cheating AI campaign$q$, $q$A single-player campaign with AI opponents designed to compete without accessing hidden information.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Large-scale multiplayer$q$, $q$Supports match sizes from 1v1 up to 16v16, along with free-for-all and cooperative modes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$PlanetWars persistent campaign$q$, $q$An ongoing, competitive online meta-game layer where match results affect a larger campaign.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Cross-platform availability$q$, $q$Playable on Windows and Linux, distributed both directly and through Steam.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Completely free with no in-game purchases or pay-to-win mechanics$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Physically simulated combat and moldable terrain add strategic depth$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Large multiplayer match sizes support big-scale battles$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Actively developed by a long-running volunteer community$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Non-cheating AI makes the single-player campaign fairer than many strategy games$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Community-developed nature means slower, less predictable release cadence than commercial studios$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Smaller player base and less polish than major commercial RTS franchises$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Steep learning curve typical of deep RTS games$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Limited marketing and visibility compared to mainstream strategy titles$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Is Zero-K free to play?$q$, $q$Yes, Zero-K is completely free with no purchase price, subscription, or in-game currency.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Is Zero-K a business or productivity tool?$q$, $q$No, Zero-K is a real-time strategy video game, not business software; it is included here as a notable free, open-source title.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$What engine does Zero-K run on?$q$, $q$Zero-K is built on the Spring engine, an open-source engine originally created for games in the Total Annihilation style.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Is Zero-K available on Steam?$q$, $q$Yes, Zero-K launched on Steam on April 27, 2018, and is also available directly from the project's own client.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Who develops Zero-K?$q$, $q$Zero-K is developed by a volunteer open-source community rather than a commercial game studio or publisher.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$What platforms does Zero-K support?$q$, $q$Zero-K supports Windows and Linux.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Does Zero-K have microtransactions?$q$, $q$No, Zero-K explicitly has no in-game currency, microtransactions, or pay-to-win mechanics.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$What is PlanetWars in Zero-K?$q$, $q$PlanetWars is a persistent, competitive online campaign in Zero-K where the outcomes of individual matches affect an ongoing meta-game across the player community.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Competitive multiplayer RTS$q$, $q$Players join large-scale multiplayer matches, from 1v1 duels to 16v16 battles, for competitive real-time strategy play.$q$, $q$Competitive RTS players$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Single-player campaign practice$q$, $q$A newer player works through the single-player campaign against non-cheating AI to learn unit roles and strategy before playing online.$q$, $q$New and casual RTS players$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Persistent community campaign$q$, $q$Dedicated players participate in PlanetWars, where ongoing match outcomes shape a larger, persistent online campaign.$q$, $q$Long-term community and clan players$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full game access","All units, maps, and commanders","PlanetWars persistent campaign","No in-game purchases"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$overview$q$, $q$What Is Zero-K$q$, 2, ARRAY[$q$Zero-K is a free, open-source real-time strategy game, not business software. It began around 2007 as a community-made mod for the Spring engine, an open-source engine originally built for Total Annihilation-style games, and evolved into a fully independent title once its remaining copyrighted content was stripped out, with the standalone project taking shape around 2010.$q$, $q$The game is built and maintained entirely by a volunteer community rather than a commercial studio or publisher. It's distributed for free with no in-game currency or microtransactions, available directly from the Zero-K project as well as on Steam, where it launched on April 27, 2018.$q$, $q$Because Zero-K is a game rather than a SaaS or business tool, it has no company headquarters, employee count, or commercial pricing structure in the conventional sense; its listing here reflects its status as a well-known, free, open-source title.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Zero-K's combat is driven by physically simulated units and projectiles rather than purely scripted outcomes, and its terrain can be actively reshaped during matches, letting players dig canals, raise ramps, or build fortifications as part of their strategy.$q$, $q$The game includes more than 100 distinct unit types with unique abilities, along with customizable commander units that let players tailor their starting strategy. A single-player campaign features AI opponents designed to compete without cheating by accessing hidden information.$q$, $q$Multiplayer support ranges from 1v1 duels to large 16v16 battles, plus free-for-all and cooperative modes. PlanetWars, a persistent online competitive campaign, ties individual match outcomes into an ongoing meta-game across the player community.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3e2e73-ff9d-46eb-852d-a3b455445f8b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zero-K is completely free to download and play, with no purchase price, subscription, or in-game currency of any kind.$q$, $q$The project explicitly markets itself as having no pay-to-win mechanics or unfair monetization, funded and developed instead by its volunteer contributor community.$q$, $q$There are no premium tiers, DLC, or paid add-ons; the entire game, including all units, maps, and the PlanetWars campaign, is available to every player at no cost.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Email and calendar$q$, $q$Integrated messaging with shared calendar coordination for individuals and teams.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Briefcase file management$q$, $q$Centralized document storage with granular, permission-based access controls.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Team chat$q$, $q$Both basic messaging and more advanced team collaboration with file sharing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Integrated office suite$q$, $q$Real-time document creation and editing without needing a separate third-party subscription.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Advanced security$q$, $q$S/MIME encryption, two-factor authentication, and mobile device management.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Compliance archiving$q$, $q$Archiving and eDiscovery tools for regulated organizations with retention requirements.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Flexible deployment$q$, $q$Runs on-premises, in a private cloud, or in a hybrid configuration for data sovereignty needs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Multi-platform access$q$, $q$Available via web client, offline desktop client, mobile via ActiveSync, and Outlook integration.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Flexible on-premises, private cloud, or hybrid deployment for data sovereignty$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Long track record with over 200 million users served over more than 20 years$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Strong fit for regulated industries needing compliance archiving and eDiscovery$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Includes an integrated office suite without needing a separate subscription$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Multiple support tiers, including 24/7 Premier support for critical issues$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Self-managed deployment options require more IT overhead than a pure SaaS suite like Google Workspace$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Publicly available pricing is limited; most organizations need a reseller quote$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Interface and ecosystem feel dated compared to newer cloud-native collaboration suites$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Licensing sold in blocks of 25 mailboxes, which can be less flexible for very small teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$What is Zimbra Collaboration used for?$q$, $q$Zimbra Collaboration is used as an email, calendar, and file-sharing suite, serving as an alternative to Microsoft Exchange or Google Workspace, especially for organizations with data sovereignty needs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Who owns Zimbra?$q$, $q$Zimbra has been owned by Synacor, a technology company headquartered in Buffalo, New York, since it acquired the product in 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Can Zimbra be deployed on-premises?$q$, $q$Yes, Zimbra can be deployed on-premises, in a private cloud, or in a hybrid configuration, giving organizations control over where their data resides.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$What is the difference between Zimbra Standard and Professional editions?$q$, $q$Standard covers core email, contacts, calendar, basic chat, and baseline security, while Professional adds Outlook connectivity, mobile push notifications, and archiving and discovery capabilities.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$How is Zimbra priced?$q$, $q$Zimbra is licensed per mailbox, typically in blocks of 25, through subscription or perpetual licensing, with reported subscription pricing of roughly $25 to $35 per user per year depending on edition, though actual quotes vary by reseller.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Does Zimbra include an office suite?$q$, $q$Yes, Zimbra includes an integrated office suite for real-time document creation and editing without requiring a separate third-party subscription.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Who typically uses Zimbra?$q$, $q$Zimbra is typically used by organizations with strict data sovereignty or compliance needs, including financial institutions, government agencies, universities, and other regulated enterprises.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Does Zimbra support mobile devices?$q$, $q$Yes, Zimbra supports mobile access via ActiveSync and offers mobile push notifications on the Professional edition.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Regulated-industry email hosting$q$, $q$A financial institution deploys Zimbra on-premises to keep email and calendar data within its own infrastructure for compliance reasons.$q$, $q$Financial services and regulated enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$University and government collaboration$q$, $q$A university or government agency uses Zimbra's private cloud deployment to manage email, calendar, and file sharing under its own data governance policies.$q$, $q$Public sector and higher education institutions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Exchange or Google Workspace migration$q$, $q$An organization moving away from Microsoft Exchange or Google Workspace adopts Zimbra Professional for Outlook connectivity during a gradual transition.$q$, $q$IT teams migrating from legacy email platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Standard$q$, $q$Approximately $25 per user per year$q$, $q$annual subscription (sold in blocks of 25 mailboxes)$q$, NULL, $q$["Email, contacts, and calendar","Basic chat","Baseline security","Standard business-hours support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Professional$q$, $q$Approximately $35 per user per year$q$, $q$annual subscription (sold in blocks of 25 mailboxes)$q$, NULL, $q$["Everything in Standard","Outlook connectivity","Mobile push notifications","Archiving and eDiscovery"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$Premier and Elite Support$q$, $q$Additional cost, custom quote$q$, $q$annual$q$, NULL, $q$["24/7 support for critical issues (Premier)","Enhanced organizational support (Elite)","Available on top of Standard or Professional editions"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$overview$q$, $q$What Is Zimbra Collaboration$q$, 2, ARRAY[$q$Zimbra Collaboration is an email, calendar, and file-sharing suite designed to give organizations an alternative to Microsoft Exchange and Google Workspace, with a particular emphasis on deployment flexibility and data control. It can run on-premises, in a private cloud, or in a hybrid setup, rather than requiring data to live in a specific vendor's public cloud.$q$, $q$The product's history stretches back to 2005, when its original developer, LiquidSys, rebranded as Zimbra, Inc. It changed hands several times over the following decade, passing through Yahoo, VMware, and Telligent Systems, before being acquired by Synacor, a technology company headquartered in Buffalo, New York, in 2015, where it remains today.$q$, $q$Zimbra reports serving more than 200 million users over its history and is used by more than 6,000 organizations across 127 countries, with a strong concentration among financial institutions, government agencies, universities, and other regulated organizations that prioritize data sovereignty.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Zimbra bundles email and calendar with shared scheduling for teams, alongside Briefcase, a file management module with granular access controls for storing and sharing documents centrally. Chat functionality ranges from basic messaging to more advanced team collaboration with file sharing.$q$, $q$Zimbra also includes an integrated office suite for real-time document creation and editing, letting organizations avoid a separate subscription to a third-party productivity suite. Security capabilities include S/MIME encryption, two-factor authentication, mobile device management, and compliance-oriented archiving and eDiscovery.$q$, $q$Access is available through a web client, an offline-capable desktop client, and mobile devices via ActiveSync, along with integration for organizations still using Microsoft Outlook, supporting gradual migration paths away from Exchange.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fac8e051-0c40-4179-bbbd-8363f2ad6985', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Zimbra is sold in two main editions: Standard, covering core email, contacts, calendar, basic chat, and baseline security, and Professional, which adds Outlook connectivity, mobile push notifications, and archiving and discovery tools.$q$, $q$Licensing is sold per mailbox, typically in blocks of 25, through either annual subscription or perpetual licensing, with separate support tiers (Standard business-hours support, Premier 24/7 support, and Elite enhanced support) priced on top.$q$, $q$Publicly available reseller pricing suggests subscription costs of roughly $25 per user per year for Standard and roughly $35 per user per year for Professional, though actual pricing varies by reseller, support tier, deployment size, and negotiated terms, so organizations should request a current quote from Synacor or an authorized Zimbra partner.$q$]::text[], 2);
