-- ── Zendesk ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Zendesk is a customer service and support platform providing ticketing, omnichannel messaging, AI-powered agents, and a help center for businesses managing customer support at scale.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$19 per agent per month (Support Team plan)$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Around 7,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Zendesk Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Zendesk's ticketing, omnichannel support, AI agents, and help center features work, plus current pricing plans and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Zendesk is a widely used customer service and support platform founded in 2007 and headquartered in San Francisco, California. It grew from a simple help-desk ticketing tool into a full customer experience suite used by tens of thousands of companies worldwide, employing roughly 7,000 people as of 2026. In November 2022, Zendesk was taken private in a roughly $10.2 billion acquisition led by investment firms Hellman and Friedman and Permira, and it continues to operate as a private company. At its core, Zendesk organizes customer conversations from email, chat, phone, and social channels into a unified ticketing system, giving support agents one place to see conversation history, customer context, and internal notes. The platform is omnichannel, meaning a single ticket can capture a conversation that starts on live chat and continues over email or phone without losing context. Zendesk has invested heavily in AI in recent years, offering AI agents that can autonomously resolve common customer questions and a Copilot layer that assists human agents with summarizing tickets, suggesting replies, and routing conversations, sold as an add-on on top of core plans. Other core capabilities include a customizable help center and knowledge base for self-service, triggers and automation for routing and escalation, a reporting and analytics layer for tracking response times and customer satisfaction, and a large app marketplace for connecting Zendesk to CRMs, e-commerce platforms, and internal tools. Zendesk's pricing is structured around agent seats billed per month, with lower prices available on annual contracts. As of 2026, the entry-level Support Team plan starts around $19 per agent per month, while the bundled Suite plans, which combine ticketing with live chat, help center, and voice, start around $55 per agent per month for Suite Team and around $115 per agent per month for Suite Professional, both on annual billing. The top Suite Enterprise tier, now marketed with Copilot AI included, is quote-only. AI features and voice or workforce management add-ons carry additional per-agent charges on top of the base plan. Zendesk primarily serves mid-market and enterprise support teams and competes with platforms including Freshdesk, Intercom, HubSpot Service Hub, and Salesforce Service Cloud.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b87bf8ae-75dd-4294-97a0-45d392ce365a';

