-- ── Zendesk Sell ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Zendesk Sell is Zendesk's sales CRM, offering pipeline management, email and activity tracking, sales forecasting, and a mobile CRM app for sales teams.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$19 per user per month (Sell Team, billed annually)$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$Around 7,000 employees (Zendesk)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Zendesk Sell Review 2026: Features, Pricing, and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Zendesk Sell's pipeline management, forecasting, mobile CRM, and automation features, plus pricing tiers and how it fits alongside Zendesk support.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Zendesk Sell is the sales CRM product within the Zendesk product family, built to give sales teams pipeline management, activity tracking, and forecasting in a product separate from Zendesk's customer support ticketing line. It runs on the same corporate infrastructure as core Zendesk, which was founded in 2007 and is headquartered in San Francisco, California, though Sell is developed, priced, and marketed as its own CRM offering rather than an add-on to the support product. At the center of Zendesk Sell is a visual sales pipeline that sales reps and managers can customize to match their own deal stages, tracking leads and deals as they move from initial contact to closed business. The product syncs with email clients like Gmail and Outlook, automatically logging email activity against the right contact or deal and supporting templates and open tracking. Built-in email and task sequences let reps automate multi-step outreach to leads without manually tracking each follow-up. Zendesk Sell also includes sales forecasting tools for predicting deal volume and revenue, roughly 20 pre-built charts and dashboards for pipeline and performance reporting, plus a drag-and-drop custom report builder for teams with specific analytics needs. A widely praised mobile CRM app for iOS and Android gives field sales reps full pipeline access plus geolocation features, letting them log calls, update deals, and see nearby prospects while traveling. Higher tiers add sales automation, a product catalog, and more advanced customization. Because Sell shares Zendesk's account infrastructure, teams that use both Zendesk Support and Zendesk Sell can connect customer service history to sales conversations, giving reps visibility into a prospect's support interactions. Zendesk Sell is priced per user per month on tiered plans: Sell Team starts around $19 per user per month annually (about $25 monthly), Sell Growth is around $55 per user per month annually (about $69 monthly), Sell Professional is around $115 per user per month annually (about $149 monthly), and Sell Enterprise runs around $169 per user per month, all billed per seat. Zendesk Sell targets small to mid-sized sales teams looking for a straightforward, activity-focused CRM, and it competes with products such as HubSpot Sales Hub, Pipedrive, and Salesforce Sales Cloud.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ab650234-f963-4681-8c8b-6976b1473d49';

