UPDATE tools SET
  short_description = COALESCE($q$Zero-K is a free, open-source real-time strategy video game featuring physically simulated units, large-scale multiplayer battles, and a persistent PlanetWars campaign, built on the Spring engine.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Zero-K Review: Free Open-Source Real-Time Strategy Game$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn about Zero-K, a free open-source RTS game with physically simulated units, terrain manipulation, large multiplayer battles, and a PlanetWars campaign.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Zero-K is a free, open-source real-time strategy (RTS) video game, not a business or productivity tool. It originated around 2007 as a community mod built on the Spring engine (an open-source engine originally created for Total Annihilation-style games), and it split off as an independent project once its copyrighted Total Annihilation content was removed, with the project's own history marking its founding around October 2010 and its first standalone release later that December. Zero-K is developed entirely by a volunteer community of contributors rather than a commercial game studio; the project describes itself as working for no publisher or corporate owner, and it emphasizes that it carries no in-game currency, microtransactions, or pay-to-win mechanics. The game is available for free on Windows and Linux, both directly from the project's own client and through Steam, where it launched on April 27, 2018. Gameplay centers on physically simulated units and projectiles, meaning combat outcomes are driven by real physics rather than purely scripted animations, and the game features destructible and moldable terrain that players can dig, raise, or flatten to build ramps, canals, or fortifications mid-battle. Zero-K includes over 100 distinct unit types with unique abilities, customizable commander units that can be built around different playstyles, and a single-player campaign with AI opponents designed not to cheat by seeing hidden information, a common complaint in other strategy game AI. Multiplayer is a major focus, supporting match sizes from small 1v1 duels up to large 16-versus-16 battles, along with free-for-all and cooperative modes against AI. A standout feature is PlanetWars, a persistent, competitive online campaign layer where player actions across matches affect an ongoing meta-game. Development has continued for well over a decade, with the community citing millions of hours of multiplayer testing and dozens of contributors adding content over time, and stable releases historically following a roughly monthly cadence. Because Zero-K is entirely free with no monetization, it has no pricing plans, subscription tiers, or company behind it in the traditional SaaS sense; it is included here as a notable, well-known piece of free software rather than a commercial product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9b3e2e73-ff9d-46eb-852d-a3b455445f8b';

